{{Short description|Moon Kami in Shinto and Japanese mythology}}
{{redirect|Tsukuyomi}}

{{Infobox deity
| type             = Japanese
| name             = Tsukuyomi-no-Mikoto
| other_names      = Tsukuyomi (ツクヨミ, 月読), Tsukiyomi (ツキヨミ), 月読尊、月弓尊、月夜見尊、月讀尊 
| god_of           = Kami of the moon
| member_of        =
| image            =Shinto-Tsukuyomi-no-Mikoto-Old-Artwork.png; File:Shinto-Tsukuyomi-no-Mikoto-Old-Artwork.png| caption          = Woodblock print of Tsukuyomi-no-Mikoto
| planet           = {{ill|Moon|en|Moon|WD=Q405|lt=Moon|1=Moon}}
